1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
17	
18	const basePremium = (item: any): number =>
19	  BASE_PREMIUMS[item.type] ?? 0;
20	
21	const groupByType = (items: any[]): Record<string, number> =>
22	  items.reduce(
23	    (counts: Record<string, number>, item: any) => ({
24	      ...counts,
25	      [item.type]: (counts[item.type] ?? 0) + 1,
26	    }),
27	    {},
28	  );
29	
30	const componentGroupPremium = (type: string, count: number): number =>
31	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
32	
33	const itemPremiumWithSurcharges = (item: any): number => {
34	  const base = basePremium(item);
35	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
36	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
37	  return base + curseSurcharge + enchantmentSurcharge;
38	};
39	
40	const quotePremium = (items: any[]): number => {
41	  const components = items.filter(isComponent);
42	  const nonComponents = items.filter((item: any) => !isComponent(item));
43	  const nonComponentTotal = nonComponents.reduce(
44	    (sum: number, item: any) => sum + itemPremiumWithSurcharges(item),
45	    0,
46	  );
47	  const componentTotal = Object.entries(groupByType(components)).reduce(
48	    (sum: number, [type, count]: [string, number]) => sum + componentGroupPremium(type, count),
49	    0,
50	  );
51	  const nonComponentBasePremium = nonComponents.reduce(
52	    (sum: number, item: any) => sum + basePremium(item),
53	    0,
54	  );
55	  const policyBasePremium = nonComponentBasePremium + componentTotal;
56	  const firstInsurance = policyBasePremium * 0.1;
57	  return Math.ceil(nonComponentTotal + componentTotal + firstInsurance + PROCESSING_FEE);
58	};
